    30→	"k8s.io/apimachinery/pkg/util/sets"
    31→	"k8s.io/apimachinery/pkg/util/wait"
    32→	"k8s.io/apiserver/pkg/endpoints/metrics"
    33→	"k8s.io/apiserver/pkg/server/httplog"
    34→	"k8s.io/component-base/metrics/prometheus/slis"
    35→	"k8s.io/klog/v2"
    36→)
    37→
    38→const DefaultHealthzPath = "/healthz"
    39→
    40→// HealthChecker is a named healthz checker.
    41→type HealthChecker interface {
    42→	Name() string
    43→	Check(req *http.Request) error
    44→}
    45→
    46→type GroupedHealthChecker interface {
    47→	HealthChecker
    48→	GroupName() string
    49→}
    50→
    51→// PingHealthz returns true automatically when checked
    52→var PingHealthz HealthChecker = ping{}
    53→
    54→// ping implements the simplest possible healthz checker.
    55→type ping struct{}
    56→
    57→func (ping) Name() string {
    58→	return "ping"
    59→}
    60→
    61→// PingHealthz is a health check that returns true.
    62→func (ping) Check(_ *http.Request) error {
    63→	return nil
    64→}
    65→
    66→// LogHealthz returns true if logging is not blocked
    67→var LogHealthz HealthChecker = &log{}
    68→
    69→type log struct {
    70→	startOnce    sync.Once
    71→	lastVerified atomic.Value
    72→}
    73→
    74→func (l *log) Name() string {
    75→	return "log"
    76→}
    77→
    78→func (l *log) Check(_ *http.Request) error {
    79→	l.startOnce.Do(func() {
    80→		l.lastVerified.Store(time.Now())
    81→		go wait.Forever(func() {
    82→			klog.Flush()
    83→			l.lastVerified.Store(time.Now())
    84→		}, time.Minute)
    85→	})
    86→
    87→	lastVerified := l.lastVerified.Load().(time.Time)
    88→	if time.Since(lastVerified) < (2 * time.Minute) {
    89→		return nil
    90→	}
    91→	return fmt.Errorf("logging blocked")
    92→}
    93→
    94→type cacheSyncWaiter interface {
    95→	WaitForCacheSync(stopCh <-chan struct{}) map[reflect.Type]bool
    96→}
    97→
    98→type informerSync struct {
    99→	cacheSyncWaiter cacheSyncWaiter
   100→}
   101→
   102→var _ HealthChecker = &informerSync{}
   103→
   104→// NewInformerSyncHealthz returns a new HealthChecker that will pass only if all informers in the given cacheSyncWaiter sync.
   105→func NewInformerSyncHealthz(cacheSyncWaiter cacheSyncWaiter) HealthChecker {
   106→	return &informerSync{
   107→		cacheSyncWaiter: cacheSyncWaiter,
   108→	}
   109→}
