   176→// "/readyz" to mux. *All handlers* for mux must be specified in
   177→// exactly one call to InstallHandler. Calling InstallHandler more
   178→// than once for the same mux will result in a panic.
   179→func InstallReadyzHandler(mux mux, checks ...HealthChecker) {
   180→	InstallPathHandler(mux, "/readyz", checks...)
   181→}
   182→
   183→// InstallLivezHandler registers handlers for liveness checking on the path
   184→// "/livez" to mux. *All handlers* for mux must be specified in
   185→// exactly one call to InstallHandler. Calling InstallHandler more
   186→// than once for the same mux will result in a panic.
   187→func InstallLivezHandler(mux mux, checks ...HealthChecker) {
   188→	InstallPathHandler(mux, "/livez", checks...)
   189→}
   190→
   191→// InstallPathHandler registers handlers for health checking on
   192→// a specific path to mux. *All handlers* for the path must be
   193→// specified in exactly one call to InstallPathHandler. Calling
   194→// InstallPathHandler more than once for the same path and mux will
   195→// result in a panic.
   196→func InstallPathHandler(mux mux, path string, checks ...HealthChecker) {
   197→	InstallPathHandlerWithHealthyFunc(mux, path, nil, checks...)
   198→}
   199→
   200→// InstallPathHandlerWithHealthyFunc is like InstallPathHandler, but calls firstTimeHealthy exactly once
   201→// when the handler succeeds for the first time.
   202→func InstallPathHandlerWithHealthyFunc(mux mux, path string, firstTimeHealthy func(), checks ...HealthChecker) {
   203→	if len(checks) == 0 {
   204→		klog.V(5).Info("No default health checks specified. Installing the ping handler.")
   205→		checks = []HealthChecker{PingHealthz}
   206→	}
   207→
   208→	klog.V(5).Infof("Installing health checkers for (%v): %v", path, formatQuoted(checkerNames(checks...)...))
   209→
   210→	name := strings.Split(strings.TrimPrefix(path, "/"), "/")[0]
   211→	mux.Handle(path,
   212→		metrics.InstrumentHandlerFunc("GET",
   213→			/* group = */ "",
   214→			/* version = */ "",
   215→			/* resource = */ "",
   216→			/* subresource = */ path,
   217→			/* scope = */ "",
   218→			/* component = */ "",
   219→			/* deprecated */ false,
   220→			/* removedRelease */ "",
   221→			handleRootHealth(name, firstTimeHealthy, checks...)))
   222→	for _, check := range checks {
   223→		mux.Handle(fmt.Sprintf("%s/%v", path, check.Name()), adaptCheckToHandler(check.Check))
   224→	}
   225→}
   226→
   227→// mux is an interface describing the methods InstallHandler requires.
   228→type mux interface {
   229→	Handle(pattern string, handler http.Handler)
   230→}
   231→
   232→// healthzCheck implements HealthChecker on an arbitrary name and check function.
   233→type healthzCheck struct {
   234→	name  string
   235→	check func(r *http.Request) error
   236→}
   237→
   238→var _ HealthChecker = &healthzCheck{}
   239→
   240→func (c *healthzCheck) Name() string {
   241→	return c.name
   242→}
   243→
   244→func (c *healthzCheck) Check(r *http.Request) error {
   245→	return c.check(r)
   246→}
   247→
   248→type groupedHealthzCheck struct {
   249→	groupName string
   250→	HealthChecker
   251→}
   252→
   253→var _ GroupedHealthChecker = &groupedHealthzCheck{}
   254→
   255→func (c *groupedHealthzCheck) GroupName() string {
   256→	return c.groupName
   257→}
   258→
   259→// getExcludedChecks extracts the health check names to be excluded from the query param
   260→func getExcludedChecks(r *http.Request) sets.String {
   261→	checks, found := r.URL.Query()["exclude"]
   262→	if found {
   263→		return sets.NewString(checks...)
   264→	}
   265→	return sets.NewString()
   266→}
   267→
   268→// handleRootHealth returns an http.HandlerFunc that serves the provided checks.
   269→func handleRootHealth(name string, firstTimeHealthy func(), checks ...HealthChecker) http.HandlerFunc {
   270→	var notifyOnce sync.Once
   271→	return func(w http.ResponseWriter, r *http.Request) {
   272→		excluded := getExcludedChecks(r)
   273→		unknownExcluded := excluded.Clone()
   274→		// failedVerboseLogOutput is for output to the log.  It indicates detailed failed output information for the log.
   275→		var failedVerboseLogOutput bytes.Buffer
   276→		var failedChecks []string
   277→		var individualCheckOutput bytes.Buffer
   278→		for _, check := range checks {
   279→			// no-op the check if we've specified we want to exclude the check
   280→			if excluded.Has(check.Name()) {
   281→				unknownExcluded.Delete(check.Name())
   282→				fmt.Fprintf(&individualCheckOutput, "[+]%s excluded: ok\n", check.Name())
   283→				continue
   284→			}
   285→			// no-op the check if it is a grouped check and we want to exclude the group
   286→			if check, ok := check.(GroupedHealthChecker); ok && excluded.Has(check.GroupName()) {
   287→				unknownExcluded.Delete(check.GroupName())
   288→				fmt.Fprintf(&individualCheckOutput, "[+]%s excluded with %s: ok\n", check.Name(), check.GroupName())
   289→				continue
   290→			}
   291→			if err := check.Check(r); err != nil {
   292→				slis.ObserveHealthcheck(context.Background(), check.Name(), name, slis.Error)
   293→				// don't include the error since this endpoint is public.  If someone wants more detail
   294→				// they should have explicit permission to the detailed checks.
   295→				fmt.Fprintf(&individualCheckOutput, "[-]%s failed: reason withheld\n", check.Name())
   296→				// but we do want detailed information for our log
   297→				fmt.Fprintf(&failedVerboseLogOutput, "[-]%s failed: %v\n", check.Name(), err)
   298→				failedChecks = append(failedChecks, check.Name())
   299→			} else {
   300→				slis.ObserveHealthcheck(context.Background(), check.Name(), name, slis.Success)
   301→				fmt.Fprintf(&individualCheckOutput, "[+]%s ok\n", check.Name())
   302→			}
   303→		}
   304→		if unknownExcluded.Len() > 0 {
   305→			fmt.Fprintf(&individualCheckOutput, "warn: some health checks cannot be excluded: no matches for %s\n", formatQuoted(unknownExcluded.List()...))
   306→			klog.V(6).Infof("cannot exclude some health checks, no health checks are installed matching %s",
   307→				formatQuoted(unknownExcluded.List()...))
   308→		}
   309→		// always be verbose on failure
   310→		if len(failedChecks) > 0 {
   311→			klog.V(2).Infof("%s check failed: %s\n%v", strings.Join(failedChecks, ","), name, failedVerboseLogOutput.String())
   312→			httplog.SetStacktracePredicate(r.Context(), func(int) bool { return false })
   313→			http.Error(w, fmt.Sprintf("%s%s check failed", individualCheckOutput.String(), name), http.StatusInternalServerError)
   314→			return
   315→		}
   316→
   317→		// signal first time this is healthy
   318→		if firstTimeHealthy != nil {
   319→			notifyOnce.Do(firstTimeHealthy)
   320→		}
   321→
   322→		w.Header().Set("Content-Type", "text/plain; charset=utf-8")
   323→		w.Header().Set("X-Content-Type-Options", "nosniff")
   324→		if _, found := r.URL.Query()["verbose"]; !found {
   325→			fmt.Fprint(w, "ok")
   326→			return
   327→		}
   328→
   329→		individualCheckOutput.WriteTo(w)
   330→		fmt.Fprintf(w, "%s check passed\n", name)
   331→	}
   332→}
   333→
   334→// adaptCheckToHandler returns an http.HandlerFunc that serves the provided checks.
   335→func adaptCheckToHandler(c func(r *http.Request) error) http.HandlerFunc {
   336→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
   337→		err := c(r)
   338→		if err != nil {
   339→			http.Error(w, fmt.Sprintf("internal server error: %v", err), http.StatusInternalServerError)
   340→		} else {
   341→			fmt.Fprint(w, "ok")
   342→		}
   343→	})
   344→}
   345→
   346→// checkerNames returns the names of the checks in the same order as passed in.
   347→func checkerNames(checks ...HealthChecker) []string {
   348→	// accumulate the names of checks for printing them out.
   349→	checkerNames := make([]string, 0, len(checks))
   350→	for _, check := range checks {
   351→		checkerNames = append(checkerNames, check.Name())
   352→	}
   353→	return checkerNames
   354→}
   355→
   356→// formatQuoted returns a formatted string of the health check names,
   357→// preserving the order passed in.
   358→func formatQuoted(names ...string) string {
   359→	quoted := make([]string, 0, len(names))
   360→	for _, name := range names {
   361→		quoted = append(quoted, fmt.Sprintf("%q", name))
   362→	}
   363→	return strings.Join(quoted, ",")
   364→}
