   346→// checkerNames returns the names of the checks in the same order as passed in.
   347→func checkerNames(checks ...HealthChecker) []string {
   348→	// accumulate the names of checks for printing them out.
   349→	checkerNames := make([]string, 0, len(checks))
   350→	for _, check := range checks {
   351→		checkerNames = append(checkerNames, check.Name())
   352→	}
   353→	return checkerNames
   354→}
